import React, { useMemo, useState } from "react";
import WeatherOverlay from "./WeatherOverlay";
import Forecast from "./Forecast";
import Radar from "./Radar";
import BottomBar from "./BottomBar";
import Chatbot from "./Chatbot";

export default function WeatherApp({
  currentCondition = "pc",
  isNight = false,
  weatherData,
}) {
  const timeOfDay = isNight ? "night" : "day";
  const overlayProps = useMemo(
    () => ({ condition: currentCondition, timeOfDay }),
    [currentCondition, timeOfDay]
  );

  const [activeTab, setActiveTab] = useState("home"); // for highlighting
  const [chatOpen, setChatOpen] = useState(false);

  // ---- helpers ----
  const scrollToId = (id) => {
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
  };

  // ---- bottom bar handlers ----
  const handleHome = () => {
    setActiveTab("home");
    window.scrollTo({ top: 0, behavior: "smooth" });
    setChatOpen(false);
  };

  const handleForecast = () => {
    setActiveTab("forecast");
    scrollToId("forecast-section");
    setChatOpen(false);
  };

  const handleRadar = () => {
    setActiveTab("radar");
    scrollToId("radar-section"); // make sure your Radar section has this id
    setChatOpen(false);
  };

  const handleChat = () => {
    setActiveTab("chat");
    setChatOpen(true);
    // optional: focus input after the sheet opens
    setTimeout(() => {
      const input = document.querySelector("#chatbot-input");
      input?.focus();
    }, 200);
  };

  return (
    <div className="relative min-h-screen flex flex-col bg-white overflow-hidden">
      {/* Background video overlays */}
      <div className="absolute top-0 left-0 w-full h-full z-0">
        <WeatherOverlay {...overlayProps} opacityMobile={0.5} />
      </div>

      {/* Main content */}
      <main className="relative z-10 flex-1">
        {/* Top section / cards */}
        <section id="top-cards" className="px-4 pt-6 pb-24 md:pb-8 max-w-5xl mx-auto">
          <div className="flex flex-col gap-4 md:gap-2">
            {/* ... your summary/weather cards here ... */}
          </div>
        </section>

        {/* Forecast section */}
        <section id="forecast-section" className="px-4 pb-24 md:pb-12 max-w-5xl mx-auto">
          <Forecast data={weatherData?.daily} />
        </section>

        {/* Radar section */}
        <section id="radar-section" className="px-4 pb-32 md:pb-12 max-w-6xl mx-auto">
          <Radar />
        </section>
      </main>

      {/* BottomBar: mobile only */}
      <BottomBar
        active={activeTab}
        onHome={handleHome}
        onForecast={handleForecast}
        onRadar={handleRadar}
        onChat={handleChat}
      />

      {/* Chat Drawer (mobile & desktop) */}
      <div
        className={[
          "fixed left-0 right-0 z-50",
          "md:right-6 md:bottom-6 md:left-auto md:w-[380px]", // desktop: float as a panel
          chatOpen ? "bottom-0" : "-bottom-[80vh] md:bottom-6 md:hidden",      // slide up on mobile
          "transition-[bottom] duration-300 ease-out",
        ].join(" ")}
        aria-hidden={!chatOpen}
      >
        <div className="mx-auto max-w-xl md:max-w-none h-[75vh] md:h-[520px] rounded-t-2xl md:rounded-2xl border border-white/10 bg-white/85 backdrop-blur shadow-xl overflow-hidden">
          {/* Header with close */}
          <div className="flex items-center gap-2 px-4 py-3 border-b border-white/20 bg-white/60">
            <div className="h-2.5 w-2.5 rounded-full bg-purple-600" />
            <div className="font-semibold text-sm">Chat</div>
            <button
              className="ml-auto text-sm px-3 py-1 rounded-lg bg-black/10 hover:bg-black/20"
              onClick={() => setChatOpen(false)}
            >
              Close
            </button>
          </div>
          <div className="h-full">
            <Chatbot
              className="h-full"
              // Give the input an id so we can focus it on open
              renderInputProps={{ id: "chatbot-input" }}
              onSend={async (message) => {
                // TODO: call your backend /api/chat with location/context
                const r = await fetch("/api/chat", {
                  method: "POST",
                  headers: { "Content-Type": "application/json" },
                  body: JSON.stringify({ message }),
                }).catch(() => null);
                if (!r || !r.ok) {
                  return { role: "assistant", content: "Sorry, I had trouble reaching the server." };
                }
                const data = await r.json();
                return { role: "assistant", content: data?.content ?? data?.message ?? "(no content)" };
              }}
            />
          </div>
        </div>
      </div>
    </div>
  );
}
